import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";
  const marketQuery = "US forces enter Iran by April 30?";

  // Phase 1: Resolve the direct market instrument and capture authoritative quote/spread data.
  const liquidity = await callMcpSkill({
    toolId,
    toolName: "analyze_market_liquidity",
    args: { marketQuery }
  });

  const tokenId = liquidity?.tokenId;
  const conditionId = liquidity?.conditionId;

  // Phase 2: Parallel read-only fetches across different endpoints for sizing analysis.
  const batch = tokenId
    ? await callMcpSkillsParallel({
        label: "iran-market-liquidity-and-parameters",
        calls: [
          {
            key: "orderbook",
            toolId,
            toolName: "get_orderbook",
            args: { tokenId, merged: true }
          },
          {
            key: "parameters",
            toolId,
            toolName: "get_market_parameters",
            args: { tokenId }
          }
        ]
      })
    : null;

  const orderbook = batch && batch.results
    ? batch.results.find((entry) => entry.key === "orderbook" && entry.status === "fulfilled")?.value
    : null;

  const parameters = batch && batch.results
    ? batch.results.find((entry) => entry.key === "parameters" && entry.status === "fulfilled")?.value
    : null;

  const asks = Array.isArray(orderbook?.asks) ? orderbook.asks : [];
  const bids = Array.isArray(orderbook?.bids) ? orderbook.bids : [];

  const bestAsk = typeof orderbook?.bestAsk === "number" ? orderbook.bestAsk : liquidity?.spread?.bestAsk ?? null;
  const bestBid = typeof orderbook?.bestBid === "number" ? orderbook.bestBid : liquidity?.spread?.bestBid ?? null;
  const midpoint =
    typeof orderbook?.midPrice === "number"
      ? orderbook.midPrice
      : bestAsk != null && bestBid != null
        ? (bestAsk + bestBid) / 2
        : null;

  const quotedSpread = {
    absolute: typeof orderbook?.spread === "number" ? orderbook.spread : liquidity?.spread?.absolute ?? null,
    bps:
      typeof liquidity?.spread?.bps === "number"
        ? liquidity.spread.bps
        : typeof liquidity?.spread?.spreadBps === "number"
          ? liquidity.spread.spreadBps
          : null,
    percentage:
      typeof liquidity?.spread?.percentage === "number"
        ? liquidity.spread.percentage
        : typeof orderbook?.spreadCents === "number"
          ? orderbook.spreadCents / 100
          : null,
    spreadCents: typeof orderbook?.spreadCents === "number" ? orderbook.spreadCents : liquidity?.spread?.spreadCents ?? null
  };

  function estimateSlippageFromBook(levels, side, notional, referencePrice) {
    if (!Array.isArray(levels) || !levels.length || !referencePrice) return null;

    const sorted = [...levels].filter((l) => typeof l?.price === "number" && typeof l?.size === "number");
    sorted.sort((a, b) => side === "buy" ? a.price - b.price : b.price - a.price);

    let remaining = notional;
    let filled = 0;
    let notionalSpentOrReceived = 0;

    for (const level of sorted) {
      if (remaining <= 0) break;
      const px = level.price;
      const qty = level.size;
      if (px <= 0 || qty <= 0) continue;

      if (side === "buy") {
        const maxQtyAtLevel = remaining / px;
        const takeQty = Math.min(qty, maxQtyAtLevel);
        const levelNotional = takeQty * px;
        filled += takeQty;
        notionalSpentOrReceived += levelNotional;
        remaining -= levelNotional;
      } else {
        const maxProceedsAtLevel = qty * px;
        const takeProceeds = Math.min(maxProceedsAtLevel, remaining);
        const takeQty = takeProceeds / px;
        filled += takeQty;
        notionalSpentOrReceived += takeProceeds;
        remaining -= takeProceeds;
      }
    }

    if (remaining > 0) return { insufficientDepth: true, filled, notionalCompleted: notional - remaining };

    const averagePrice = side === "buy"
      ? notionalSpentOrReceived / filled
      : notionalSpentOrReceived / filled;

    const slippagePercent =
      side === "buy"
        ? ((averagePrice - referencePrice) / referencePrice) * 100
        : ((referencePrice - averagePrice) / referencePrice) * 100;

    return {
      side,
      notional,
      averagePrice,
      referencePrice,
      slippagePercent,
      filled,
      depthUsed: notionalSpentOrReceived
    };
  }

  const buy25k = estimateSlippageFromBook(asks, "buy", 25000, midpoint || bestAsk || liquidity?.currentPrice || null);
  const sell25k = estimateSlippageFromBook(bids, "sell", 25000, midpoint || bestBid || liquidity?.currentPrice || null);

  return {
    market: liquidity?.market ?? marketQuery,
    tokenId: tokenId ?? null,
    conditionId: conditionId ?? null,
    bestBid,
    bestAsk,
    midpoint,
    quotedSpread,
    tickSize: parameters?.tickSize ?? null,
    feeRateBps: parameters?.feeRateBps ?? null,
    negRisk: parameters?.negRisk ?? null,

