      limit: 10
    }
  });

  const candidates = Array.isArray(discovery?.results) ? discovery.results : [];
  const ranked = pickTopSemanticCandidates({
    target: query,
    candidates,
    requiredTerms: ["strait", "hormuz", "traffic", "normal", "april"],
    avoidTerms: ["similar", "related", "proxy", "secondary"],
    limit: 3
  });

  const chosen = ranked?.[0] || candidates[0] || null;
  if (!chosen || (!chosen.slug && !chosen.conditionId)) {
    return {
      missingData: "Could not resolve a usable market identifier",
      attemptedBranches: ["search_markets", "semantic_ranking"],
      stopReason: "No suitable candidate returned from discovery"
    };
  }

  const identifierArgs = chosen.slug
    ? { slug: chosen.slug }
    : { conditionId: chosen.conditionId };

  const detailBatch = await callMcpSkillsParallel({
    label: "strait-of-hormuz-rules-and-price",
    calls: [
      {
        key: "rules",
        toolId,
        toolName: "check_market_rules",
        args: identifierArgs
      },
      {
        key: "liquidity",
        toolId,
        toolName: "analyze_market_liquidity",
        args: identifierArgs
      }
    ]
  });

  const rulesResult =
    detailBatch.results.find((entry) => entry.key === "rules")?.status === "fulfilled"
      ? detailBatch.results.find((entry) => entry.key === "rules").value
      : null;

  const liquidityResult =
    detailBatch.results.find((entry) => entry.key === "liquidity")?.status === "fulfilled"
      ? detailBatch.results.find((entry) => entry.key === "liquidity").value
      : null;

  const resolutionLanguage = rulesResult?.description || null;
  const deadline = rulesResult?.endDate || chosen.endDate || null;
  const currentPrice =
    typeof liquidityResult?.currentPrice === "number"
      ? liquidityResult.currentPrice
      : typeof chosen.currentPrice === "number"
        ? chosen.currentPrice
        : null;

  const gotchas = Array.isArray(rulesResult?.rulesSummary?.potentialGotchas)
    ? rulesResult.rulesSummary.potentialGotchas
    : [];
  const ambiguities = Array.isArray(rulesResult?.rulesSummary?.ambiguities)
    ? rulesResult.rulesSummary.ambiguities
    : [];

  const extremePrice =
    typeof currentPrice === "number" && (currentPrice <= 0.05 || currentPrice >= 0.95);

  const highRulesRisk = gotchas.length > 0 || ambiguities.length > 0 || extremePrice;
  const lowRulesRisk = !highRulesRisk && !!resolutionLanguage && currentPrice !== null;

  return {
    market: rulesResult?.market || chosen.title || query,
    selectedCandidate: {
      title: chosen.title || null,
      slug: chosen.slug || null,
      conditionId: chosen.conditionId || null
    },
    resolutionLanguage,
    deadline,
    currentPrice,
    rulesRisk: highRulesRisk ? "high" : lowRulesRisk ? "low" : "moderate",
    riskRead: highRulesRisk
      ? "High rules-risk: the wording has ambiguity/gotchas, or price is near one-sided and more vulnerable to resolution sensitivity."
      : "Low rules-risk: the resolution language is cleaner, the deadline is explicit, and the current price is not near a one-sided edge.",
    riskFactors: gotchas,
    ambiguities,
    attemptedBranches: ["search_markets", "pickTopSemanticCandidates", "check_market_rules", "analyze_market_liquidity"],
    parallelTelemetry: detailBatch.summary
  };
}

