import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const result = await callMcpSkill({
    toolId: "294100e8-c648-4e5f-a254-95a14b56e398",
    toolName: "analyze_top_holders",
    args: {
      marketQuery: "Will Vicky Dávila win the 2026 Colombian presidential election?"
    }
  });

  const yesWhales = Array.isArray(result?.whaleAnalysis?.yesWhales) ? result.whaleAnalysis.yesWhales : [];
  const noWhales = Array.isArray(result?.whaleAnalysis?.noWhales) ? result.whaleAnalysis.noWhales : [];

  const topYesValue = yesWhales.length > 0 ? yesWhales[0].positionValue : null;
  const topNoValue = noWhales.length > 0 ? noWhales[0].positionValue : null;

  const concentration = result?.marketConcentration || null;
  const signal = result?.smartMoneySignal || null;

  let supportRead = "insufficient_data";
  if (concentration && typeof concentration.whaleCount === "number") {
    if (
      (typeof concentration.top5YesPercent === "number" && concentration.top5YesPercent >= 70) ||
      (typeof concentration.top5NoPercent === "number" && concentration.top5NoPercent >= 70) ||
      (typeof concentration.whaleCount === "number" && concentration.whaleCount <= 5)
    ) {
      supportRead = "likely_concentrated";
    } else {
      supportRead = "more_broadly_distributed";
    }
  }

  return {
    market: result?.market || "Will Vicky Dávila win the 2026 Colombian presidential election?",
    conditionId: result?.conditionId || null,
    fetchedAt: result?.fetchedAt || null,
    currentPrice: result?.currentPrice ?? null,
    smartMoneySignal: signal,
    marketConcentration: concentration,
    topHolders: {
      yes: yesWhales.slice(0, 5),
      no: noWhales.slice(0, 5)
    },
