  ];

  for (const candidate of directCandidates) {
    if (Array.isArray(candidate)) {
      return candidate;
    }
  }

  const nestedData =
    value.data && typeof value.data === "object" ? value.data : null;
  if (!nestedData) {
    return [];
  }

  const nestedCandidates = [
    nestedData.results,
    nestedData.items,
    nestedData.rows,
    nestedData.markets,
    nestedData.events,
    nestedData.entries,
    nestedData.records,
    nestedData.candidates,
    nestedData.data,
  ];

  for (const candidate of nestedCandidates) {
    if (Array.isArray(candidate)) {
      return candidate;
    }
  }

  return [];
