    (Array.isArray(liquidityResult?.analyzedOutcomes) ? liquidityResult.analyzedOutcomes : []).map((x) => [
      x.matchedName,
      x,
    ])
  );

  const whaleByName = new Map(
    (Array.isArray(whaleResult?.whalesByOutcome) ? whaleResult.whalesByOutcome : []).map((x) => [
      x.outcome,
      x,
    ])
  );

  const merged = outcomes.map((o) => {
    const liquidity = liquidityByName.get(o.name) || {};
    const whales = whaleByName.get(o.name) || {};
    return {
      name: o.name,
      price: toNum(o.price),
      volume: toNum(o.volume),
      currentPrice: toNum(o.price),
      spreadCents: toNum(liquidity.spreadCents),
      totalDepthUsd: toNum(liquidity.totalDepthUsd),
      slippage1kPercent: toNum(liquidity.slippage1kPercent),
      slippage5kPercent: toNum(liquidity.slippage5kPercent),
      slippage10kPercent: toNum(liquidity.slippage10kPercent),
      liquidityScore: liquidity.liquidityScore || null,
      whaleCount: toNum(whales.whaleCount),
      totalWhaleValue: toNum(whales.totalWhaleValue),
      topWhalePosition: toNum(whales.topWhalePosition),
      convictionLevel: whales.convictionLevel || null,
    };
  });

  const bestTradeable = merged
    .filter(isTradeableLiquidity)
    .sort((a, b) => {
      const depthA = toNum(a.totalDepthUsd) ?? 0;
      const depthB = toNum(b.totalDepthUsd) ?? 0;
      const spreadA = toNum(a.spreadCents) ?? 999;
      const spreadB = toNum(b.spreadCents) ?? 999;
      const whaleA = toNum(a.totalWhaleValue) ?? 0;
      const whaleB = toNum(b.totalWhaleValue) ?? 0;
      return depthB - depthA || spreadA - spreadB || whaleB - whaleA;
    });

  const expensiveButUntradeable = merged
    .filter(isExpensiveButUntradeable)
    .sort((a, b) => (toNum(b.currentPrice) ?? 0) - (toNum(a.currentPrice) ?? 0));

  return {
    eventTitle,
    eventSlug,
    semanticShortlist: shortlistedOutcomes.map((o) => o?.name).filter(Boolean),
    bestCombination: bestTradeable.slice(0, 5),
    expensiveButUntradeable: expensiveButUntradeable.slice(0, 5),
    analysisNotes

