import { callMcpSkill, callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

function toNum(x) {
  return typeof x === "number" && Number.isFinite(x) ? x : null;
}

function isTradeableLiquidity(x) {
  const depth = toNum(x?.totalDepthUsd) ?? 0;
  const spread = toNum(x?.spreadCents) ?? 999;
  const slippage5k = toNum(x?.slippage5kPercent) ?? 999;
  return depth >= 25000 && spread <= 4 && slippage5k <= 5;
}

function isExpensiveButUntradeable(x) {
  const price = toNum(x?.currentPrice) ?? 0;
  const depth = toNum(x?.totalDepthUsd) ?? 0;
  const spread = toNum(x?.spreadCents) ?? 0;
  const slippage5k = toNum(x?.slippage5kPercent) ?? 0;
  const liquidityScore = x?.liquidityScore || "";
  return price >= 0.20 && (depth < 15000 || spread > 6 || slippage5k > 8 || liquidityScore === "poor" || liquidityScore === "illiquid");
}

export async function main() {
  const eventQuery = "The Masters - Winner";

  const discovery = await callMcpSkill({
    toolId,
    toolName: "search_and_get_outcomes",
    args: {
      query: eventQuery,
      category: "sports",
      sortBy: "volume",
    },
  });

  const eventTitle = discovery?.eventTitle || null;
  const eventSlug = discovery?.eventSlug || null;
  const outcomes = Array.isArray(discovery?.outcomes) ? discovery.outcomes : [];

  const semanticShortlist = pickTopSemanticCandidates({
    target: "representative favorite winner markets for a major golf event, prioritizing current favorites and the most likely tradable outcome markets",
    candidates: outcomes,
    requiredTerms: ["golf", "winner"],
    avoidTerms: ["round", "matchup", "top 5", "prop"],
    limit: 8,
  });

  const shortlistedOutcomes = semanticShortlist.map((x) => x.candidate);

  const analysisBatch = await callMcpSkillsParallel({
    label: "masters-winner-liquidity-and-whales",
    calls: [
      {
        key: "liquidity",
        toolId,
        toolName: "analyze_event_outcome_liquidity",
        args: {
          eventQuery,
          category: "sports",
          outcomes: shortlistedOutcomes.map((o) => o?.name).filter(Boolean),
          limit: Math.min(shortlistedOutcomes.length || 4, 8),
          sortBy: "price",
        },
      },
      {
        key: "whales",
        toolId,
        toolName: "analyze_event_whale_breakdown",
        args: {
          marketQuery: eventQuery,
          maxOutcomes: 8,
        },
      },
    ],
  });

  const liquidityResult =
    analysisBatch.results.find((x) => x.key === "liquidity")?.status === "fulfilled"
      ? analysisBatch.results.find((x) => x.key === "liquidity").value
      : null;

  const whaleResult =
    analysisBatch.results.find((x) => x.key === "whales")?.status === "fulfilled"
      ? analysisBatch.results.find((x) => x.key === "whales").value
      : null;

  const liquidityByName = new Map(
    (Array.isArray(liquidityResult?.analyzedOutcomes) ? liquidityResult.analyzedOutcomes : []).map((x) => [
      x.matchedName,
      x,
    ])
  );

  const whaleByName = new Map(
    (Array.isArray(whaleResult?.whalesByOutcome) ? whaleResult.whalesByOutcome : []).map((x) => [
      x.outcome,
      x,
    ])
  );

  const merged = outcomes.map((o) => {
    const liquidity = liquidityByName.get(o.name) || {};
    const whales = whaleByName.get(o.name) || {};
    return {
      name: o.name,
      price: toNum(o.price),
      volume: toNum(o.volume),
      currentPrice: toNum(o.price),
      spreadCents: toNum(liquidity.spreadCents),
      totalDepthUsd: toNum(liquidity.totalDepthUsd),
      slippage1kPercent: toNum(liquidity.slippage1kPercent),
      slippage5kPercent: toNum(liquidity.slippage5kPercent),
      slippage10kPercent: toNum(liquidity.slippage10kPercent),
      liquidityScore: liquidity.liquidityScore || null,
      whaleCount: toNum(whales.whaleCount),
      totalWhaleValue: toNum(whales.totalWhaleValue),
      topWhalePosition: toNum(whales.topWhalePosition),
      convictionLevel: whales.convictionLevel || null,
    };
  });

  const bestTradeable = merged
    .filter(isTradeableLiquidity)
    .sort((a, b) => {
      const depthA = toNum(a.totalDepthUsd) ?? 0;
      const depthB = toNum(b.totalDepthUsd) ?? 0;
      const spreadA = toNum(a.spreadCents) ?? 999;
      const spreadB = toNum(b.spreadCents) ?? 999;
      const whaleA = toNum(a.totalWhaleValue) ?? 0;
      const whaleB = toNum(b.totalWhaleValue) ?? 0;
      return depthB - depthA || spreadA - spreadB || whaleB - whaleA;
    });

  const expensiveButUntradeable = merged
    .filter(isExpensiveButUntradeable)
    .sort((a, b) => (toNum(b.currentPrice) ?? 0) - (toNum(a.currentPrice) ?? 0));

  return {
    eventTitle,
    eventSlug,
    semanticShortlist: shortlistedOutcomes.map((o) => o?.name).filter(Boolean),
    bestCombination: bestTradeable.slice(0, 5),
    expensiveButUntradeable: expensiveButUntradeable.slice(0, 5),
    analysisNotes

